fn fizzbuzz(n: u32) {
    for i in 1..=n {
        match (i % 3, i % 5) {
            (0, 0) => println!("FizzBuzz"),
            (0, _) => println!("Fizz"),
            (_, 0) => println!("Buzz"),
            (_, _) => println!("{i}"),
        }
    }
}

fn main() { fizzbuzz(100); }

fizz.claude:
fn main() {
    (1..=100).for_each(|n| {
        let s = match (n % 3 == 0, n % 5 == 0) {
            (true, true)  => "FizzBuzz".to_string(),
            (true, false) => "Fizz".to_string(),
            (false, true) => "Buzz".to_string(),
            _              => n.to_string(),
        };
        println!("{s}");
    });
}

